{"code": "import json

# Get all books in Literature & Fiction category
books_key = 'var_functions.query_db:26'
books_result = locals().get(books_key)

if isinstance(books_result, str):
    with open(books_result, 'r') as f:
        books = json.load(f)
else:
    books = books_result

# Filter for English-language (we'll check details field contains "English")
english_books = []
for book in books:
    details = book.get('details', '')
    if 'English' in details or 'english' in details:
        english_books.append(book)

# Extract book IDs and titles
book_info = {book['book_id']: book['title'] for book in english_books}

print('__RESULT__:')
print(json.dumps({
    'total_books': len(books),
    'english_books_count': len(english_books),
    'book_ids': list(book_info.keys())[:10],  # Sample of book IDs
    'sample_titles': list(book_info.values())[:5]
}))"}

